// Time:  O(k * e * t)
// Space: O(n * t)

// dp
class Solution {
public:
    int maxWeight(int n, vector<vector<int>>& edges, int k, int t) {
        vector<vector<pair<int, int>>> adj(n + 1);
        for (const auto& e : edges) {
            adj[e[0]].emplace_back(e[1], e[2]);
        }
        vector<unordered_set<int>> dp(n);
        for (int i = 0; i < n; ++i) {
            dp[i].emplace(0);
        }
        for (int _ = 0; _ < k; ++_) {
            vector<unordered_set<int>> new_dp(n);
            for (int i = 0; i < n; ++i) {
                for (const auto& c : dp[i]) {
                    for (const auto& [j, w] : adj[i]) {
                        if (c + w < t) {
                            new_dp[j].emplace(c + w);
                        }
                    }
                }
            }
            dp = move(new_dp);
        }
        int result = -1;
        for (const auto& x : dp) {
            if (!empty(x)) {
                result = max(result, ranges::max(x));
            }
        }
        return result;
    }
};

# Time:  O(k * e * t)
# Space: O(n * t)

# dp
class Solution(object):
    def maxWeight(self, n, edges, k, t):
        """
        :type n: int
        :type edges: List[List[int]]
        :type k: int
        :type t: int
        :rtype: int
        """
        adj = [[] for _ in xrange(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
        dp = [{0} for _ in xrange(n)]
        for _ in xrange(k):
            new_dp = [set() for _ in xrange(n)]
            for i in xrange(n):
                for c in dp[i]:
                    for j, w in adj[i]:
                        if c+w < t:
                            new_dp[j].add(c+w)
            dp = new_dp
        result = -1
        for x in dp:
            if x:
                result = max(result, max(x))
        return result
